/**
 * Adapter: UI and utility re-exports for copy-standalone portability.
 *
 * When copying this component to another project, update these imports
 * to match your project's paths:
 *
 *   cn      → Your Tailwind merge utility (e.g., "@/lib/utils", "~/lib/cn")
 *   Button  → shadcn/ui Button
 *   Tooltip → shadcn/ui Tooltip
 */

export { cn } from "../../../lib/ui/cn";
export { Button } from "../../ui/button";
export {
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "../../ui/tooltip";

export { InstagramPost } from "./instagram-post";
export type { InstagramPostProps } from "./instagram-post";
export {
  SerializableInstagramPostSchema,
  parseSerializableInstagramPost,
  safeParseSerializableInstagramPost,
} from "./schema";
export type {
  InstagramPostData,
  InstagramPostAuthor,
  InstagramPostMedia,
  InstagramPostStats,
} from "./schema";

"use client";

import * as React from "react";
import { BadgeCheck, Heart, Share } from "lucide-react";
import {
  cn,
  Button,
  Tooltip,
  TooltipContent,
  TooltipProvider,
  TooltipTrigger,
} from "./_adapter";import { ActionButtons } from "../shared/action-buttons";
import { normalizeActionsConfig, type ActionsProp } from "../shared/actions-config";
import { formatRelativeTime } from "../shared/utils";

import type { InstagramPostData, InstagramPostMedia } from "./schema";

export interface InstagramPostProps {
  post: InstagramPostData;
  className?: string;
  onAction?: (action: string, post: InstagramPostData) => void;
  responseActions?: ActionsProp;
  onResponseAction?: (actionId: string) => void | Promise<void>;
  onBeforeResponseAction?: (actionId: string) => boolean | Promise<boolean>;
}

